window['listing'] = {
	current_sbss_id: null,
	editModalSBG(sbss_id){
		$.post("api/MM_API_GLOBAL_SETUPCARIANSBG?getDataModal=1", { sbss_id: sbss_id }, function(data){
			for(key in data.dataModal){
				$("#"+key).val(data.dataModal[key])
			}
			listing.current_sbss_id = data.dataModal['sbss_id']
			$('#jenisCarianModal').modal('show')
		}, "json");
	},
	editBillSetup(bis_id){
		$.post("api/MM_API_GLOBAL_SETUPCARIANSBG?getDataBillSetup=1", { bis_id: bis_id }, function(data){
			for(key in data.dataModal){
				$("#"+key).val(data.dataModal[key])
			}
			listing.current_bis_id = data.dataModal['bis_id']
			$('#billSetupModal').modal('show')
		}, "json");
	},
	saveModal(){
		$('.btn').toggleSpinner()
		$.post("api/MM_API_GLOBAL_SETUPCARIANSBG?saveModal=1", { sbss_id: listing.current_sbss_id, dataModal: $('#jenisCarianModal :input').serializeJson() }, function(data){
			$('.btn').toggleSpinner()
			if(data.status == 'ok'){
				dt_listing.draw()
				$('#jenisCarianModal').modal('hide')
				showModal({
					content: LANG_INSERT_SUCCESS
				})
			}else{
				showModal({
					content: LANG_INSERT_ERROR
				})
			}
		}, "json");
	},
	billSetupSave(){
		$('.btn').toggleSpinner()
		$.post("api/MM_API_GLOBAL_SETUPCARIANSBG?saveBillSetupModal=1", { bis_id: listing.current_bis_id, dataModal: $('#billSetupModal :input').serializeJson() }, function(data){
			$('.btn').toggleSpinner()
